import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { Input, Btn, toast } from '../components/ui';
import { Lock, Mail, ArrowRight } from 'lucide-react';

const DEMO_USERS = [
  { label: 'Admin', email: 'admin@skips.edu', password: 'admin123' },
  { label: 'HR', email: 'hr@skips.edu', password: 'hr123' },
  { label: 'HOD', email: 'hod@skips.edu', password: 'hod123' },
  { label: 'Accountant', email: 'acc@skips.edu', password: 'acc123' },
  { label: 'Employee', email: 'emp@skips.edu', password: 'emp123' },
];

export default function Login() {
  const { login, loading } = useAuth();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) {
      toast('Please enter email and password', 'warning');
      return;
    }
    const result = await login(email, password);
    if (!result.ok) {
      toast(result.error || 'Login failed', 'error');
    }
  };

  const handleDemoLogin = async (demo) => {
    setEmail(demo.email);
    setPassword(demo.password);
    const result = await login(demo.email, demo.password);
    if (!result.ok) {
      toast(result.error || 'Login failed', 'error');
    }
  };

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <div className="logo-icon">
            <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="white" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2" />
              <circle cx="9" cy="7" r="4" />
              <path d="M23 21v-2a4 4 0 0 0-3-3.87" />
              <path d="M16 3.13a4 4 0 0 1 0 7.75" />
            </svg>
          </div>
          <h1>UniHRM</h1>
          <p>University Human Resource Management</p>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ position: 'relative' }}>
            <Input
              label="Email Address"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="Enter your email"
              required
              id="login-email"
            />
          </div>
          <div style={{ position: 'relative' }}>
            <Input
              label="Password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              required
              id="login-password"
            />
          </div>
          <Btn
            type="submit"
            loading={loading}
            style={{
              width: '100%',
              padding: '10px 20px',
              fontSize: 14,
              fontWeight: 600,
              marginTop: 4,
              background: 'linear-gradient(135deg, #1B6EF3 0%, #1458CC 100%)',
              boxShadow: '0 4px 14px rgba(27, 110, 243, 0.35)',
              borderRadius: 'var(--radius)',
              letterSpacing: '-0.01em',
            }}
          >
            Sign In <ArrowRight size={16} />
          </Btn>
        </form>

        <div className="demo-logins">
          <h4>Quick Demo Access</h4>
          <div className="demo-pills">
            {DEMO_USERS.map((d) => (
              <button
                key={d.email}
                className="demo-pill"
                onClick={() => handleDemoLogin(d)}
                disabled={loading}
                type="button"
              >
                {d.label}
              </button>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
